#!/bin/bash

${1:# Script description}

set -euo pipefail

${2:# Main code}

if [ ${1:condition} ]; then
	${2:# commands}
else
	${3:# alternative}
fi

if [ ${1:condition1} ]; then
	${2:# commands1}
elif [ ${3:condition2} ]; then
	${4:# commands2}
else
	${5:# default}
fi

for ${1:item} in ${2:list}; do
	${3:# process item}
done

while [ ${1:condition} ]; do
	${2:# commands}
done

while IFS= read -r ${1:line}; do
	${2:# process line}
done < "${3:file.txt}"

case ${1:$var} in
	${2:pattern1})
		${3:# commands1}
		;;
	${4:pattern2})
		${5:# commands2}
		;;
	*)
		${6:# default}
		;;
esac

${1:function_name}() {
	${2:# function body}
}

${1:function_name}() {
	local ${2:arg1}="$1"
	local ${3:arg2}="${2:-default}"

	${4:# function body}

	return 0
}

while getopts "${1:ab:c}" opt; do
	case $opt in
		${2:a})
			${3:# handle -a}
			;;
		${4:b})
			${5:value}="$OPTARG"
			;;
		${6:c})
			${7:# handle -c}
			;;
		\?)
			echo "Invalid option: -$OPTARG" >&2
			exit 1
			;;
	esac
done
shift $((OPTIND - 1))

error_exit() {
	echo "Error: $1" >&2
	exit ${2:-1}
}

cleanup() {
	${1:# cleanup code}
}

trap cleanup EXIT

cat <<EOF
${1:Text with $variable expansion}
EOF

cat <<'EOF'
${1:Text with literal $variable}
EOF
